CREATE FUNCTION fn_customer_support_ticket_duration(ticketId VARCHAR(255))
RETURNS INT
DETERMINISTIC
BEGIN
    DECLARE ticketDuration INT;
    SELECT DATEDIFF(resolved_at, created_at)
    INTO ticketDuration
    FROM support_tickets
    WHERE ticket_id = ticketId;
    RETURN ticketDuration;
END;
